    <p class="text-center">{% trans "You are entering the admin area. Confirm with Microsoft to continue." %}</p>

    <button id="sso" type="button" class="btn btn-block ms-signin-button" aria-label="Sign in with Microsoft">
      <svg class="ms-signin-logo" viewBox="0 0 23 23" role="img" aria-hidden="true" focusable="false">
        <rect x="1" y="1" width="10" height="10" fill="#f25022"></rect>
